<section class="page-hero shell section-space-small"><p class="eyebrow">UN ULTIM DETALIU</p><h1>Finalizare comandă</h1><p>Completează datele, iar noi pregătim fiecare produs cu grijă.</p></section>
<form class="checkout-layout shell section-space-small" method="post" action="<?= e(url('/checkout/create')) ?>" data-checkout-form><?= csrf_field() ?><input type="hidden" name="idempotency_key" value="<?= e($idempotency) ?>">
<div class="checkout-fields"><section class="form-card"><h2>Date personale</h2><div class="customer-type"><label><input type="radio" name="customer_type" value="individual" checked> Persoană fizică</label><label><input type="radio" name="customer_type" value="company"> Persoană juridică</label></div><div class="form-grid"><label>Prenume *<input name="first_name" required autocomplete="given-name" value="<?= e($checkoutCustomer['first_name']??'') ?>"></label><label>Nume *<input name="last_name" required autocomplete="family-name" value="<?= e($checkoutCustomer['last_name']??'') ?>"></label><label>Email *<input type="email" name="email" required autocomplete="email" value="<?= e($checkoutCustomer['email']??'') ?>"></label><label>Telefon *<input name="phone" required autocomplete="tel" value="<?= e($checkoutAddress['phone']??($checkoutCustomer['phone']??'')) ?>"></label></div><div class="company-fields" hidden data-company-fields><div class="form-grid"><label>Denumire companie *<input name="company_name"></label><label>CUI/CIF *<input name="tax_id"></label><label>Nr. Registrul Comerțului<input name="registration_number"></label></div></div></section>
<section class="form-card"><h2>Adresă de facturare și livrare</h2><?php if($savedAddresses): ?><label class="span-2 checkout-saved-address">Adresă salvată<select data-checkout-address><option value="new">Adaugă o adresă nouă</option><?php foreach($savedAddresses as $address): $payload=json_encode(['first_name'=>$address['contact_first_name']?:($checkoutCustomer['first_name']??''),'last_name'=>$address['contact_last_name']?:($checkoutCustomer['last_name']??''),'phone'=>$address['phone']?:($checkoutCustomer['phone']??''),'address'=>$address['line1'],'address_2'=>$address['line2']??'','city'=>$address['city'],'county'=>$address['county']??'','postal_code'=>$address['postal_code']??''],JSON_UNESCAPED_UNICODE|JSON_UNESCAPED_SLASHES); ?><option value="<?= (int)$address['id'] ?>" data-address="<?= e($payload) ?>" <?= $address['is_default']?'selected':'' ?>><?= e($address['name'].' · '.$address['line1'].', '.$address['city']) ?></option><?php endforeach; ?></select></label><?php endif; ?><div class="form-grid"><label class="span-2">Adresă *<input name="address" required autocomplete="street-address" value="<?= e($checkoutAddress['line1']??'') ?>"></label><label class="span-2">Detalii adresă<input name="address_2" value="<?= e($checkoutAddress['line2']??'') ?>"></label><label>Localitate *<input name="city" required value="<?= e($checkoutAddress['city']??'') ?>"></label><label>Județ *<input name="county" required value="<?= e($checkoutAddress['county']??'') ?>"></label><label>Cod poștal *<input name="postal_code" required autocomplete="postal-code" value="<?= e($checkoutAddress['postal_code']??'') ?>"></label></div><?php if($checkoutCustomer): ?><div class="checkout-save-address"><label class="toggle-switch"><input type="checkbox" name="save_address" value="1"><span class="switch-track"><i></i></span><b>Salvează această adresă în cont</b></label><label data-address-label hidden>Etichetă adresă<input name="address_label" placeholder="Acasă"></label></div><?php endif; ?></section>
<section class="form-card"><h2>Livrare</h2><label class="choice-card"><input type="radio" name="shipping_method" value="courier" checked><span><strong>Curier la adresă</strong><small><?= $totals['shipping_minor']?money($totals['shipping_minor']):'Gratuit' ?></small></span></label></section>
<section class="form-card"><h2>Plată</h2><?php foreach($providers as $index=>$provider): ?><label class="choice-card"><input type="radio" name="payment_method" value="<?= e($provider['code']) ?>" <?= $index===0?'checked':'' ?>><span><strong><?= e($provider['name']) ?></strong><small><?= $provider['provider_type']==='cod'?'Plătești la primirea coletului':'Vei continua către plata securizată' ?></small></span></label><?php endforeach; ?></section>
<section class="form-card"><h2>Mesaj cadou</h2><label class="span-2">Mesaj opțional<textarea name="gift_message" maxlength="500"></textarea></label></section></div>
<aside class="checkout-summary"><h2>Sumar comandă</h2><?php foreach($totals['items'] as $item): $custom=json_decode((string)($item['customization_json']??''),true)?:[]; ?><div class="checkout-item"><img src="<?= e(url($item['image_path'])) ?>" alt="" width="58" height="70"><span><strong><?= e($item['name']) ?></strong><small><?= (int)$item['quantity'] ?> × <?= money($item['price_minor']) ?></small><?php if(($custom['type']??'')==='gift_box'): ?><small class="gift-cart-note"><?= ($custom['role']??'')==='component'?'Componentă pentru':'Cutie' ?> <?= e($custom['template_name']??'Gift Box') ?></small><?php endif; ?></span></div><?php endforeach; ?><div><span>Subtotal</span><strong><?= money($totals['subtotal_minor']) ?></strong></div><div><span>Reducere</span><strong>-<?= money($totals['discount_minor']) ?></strong></div><div><span>Livrare</span><strong><?= $totals['shipping_minor']?money($totals['shipping_minor']):'Gratuit' ?></strong></div><div class="summary-total"><span>Total</span><strong><?= money($totals['grand_total_minor']) ?></strong></div><label class="terms"><input type="checkbox" name="terms" value="1" required> Sunt de acord cu <a href="<?= e(url('/politici/termeni-si-conditii')) ?>" target="_blank">termenii și condițiile</a>.</label><button class="button" type="submit">Plasează comanda</button><p class="secure-note">Datele și totalurile sunt validate securizat pe server.</p></aside></form>
<script>document.querySelectorAll('input[name="customer_type"]').forEach(i=>i.addEventListener('change',()=>{const c=document.querySelector('[data-company-fields]');c.hidden=i.value!=='company';c.querySelectorAll('input').forEach(x=>x.required=i.value==='company'&&['company_name','tax_id'].includes(x.name));}));</script>